#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    char s1[101], s2[101];
    for(int i=0;i<T;++i){
        if(!fgets(s1, sizeof(s1), stdin)) break;
        if(!fgets(s2, sizeof(s2), stdin)) break;
        s1[strcspn(s1, "\n")] = '\0';
        s2[strcspn(s2, "\n")] = '\0';
        printf("%s %s\n", s1, s2);
    }
    return 0;
}

